import{_ as a,o as s,c as r,a2 as o}from"./chunks/framework.DCVnL8g5.js";const m=JSON.parse('{"title":"Procesadores, controller services y parametros","description":"","frontmatter":{},"headers":[],"relativePath":"data-engineering/nifi/04-procesadores-controller-services-y-parametros.md","filePath":"data-engineering/nifi/04-procesadores-controller-services-y-parametros.md","lastUpdated":1782521464000}'),i={name:"data-engineering/nifi/04-procesadores-controller-services-y-parametros.md"};function n(l,e,t,c,p,d){return s(),r("div",null,[...e[0]||(e[0]=[o(`<h1 id="procesadores-controller-services-y-parametros" tabindex="-1">Procesadores, controller services y parametros <a class="header-anchor" href="#procesadores-controller-services-y-parametros" aria-label="Permalink to &quot;Procesadores, controller services y parametros&quot;">​</a></h1><p>Los procesadores hacen el trabajo visible, pero los controller services y los parametros hacen que el flujo sea mantenible.</p><h2 id="ciclo-de-vida-de-un-processor" tabindex="-1">Ciclo de vida de un processor <a class="header-anchor" href="#ciclo-de-vida-de-un-processor" aria-label="Permalink to &quot;Ciclo de vida de un processor&quot;">​</a></h2><p>Un processor puede estar:</p><ul><li><strong>Stopped:</strong> configurado pero sin ejecutar.</li><li><strong>Running:</strong> ejecutando segun su planificacion.</li><li><strong>Invalid:</strong> falta configuracion o algun servicio requerido.</li><li><strong>Disabled:</strong> desactivado manualmente.</li></ul><p>Antes de arrancar un flujo, revisa los processors invalidos. Un icono de advertencia suele indicar propiedades incompletas, relationships sin resolver o controller services no habilitados.</p><h2 id="propiedades" tabindex="-1">Propiedades <a class="header-anchor" href="#propiedades" aria-label="Permalink to &quot;Propiedades&quot;">​</a></h2><p>Cada processor tiene propiedades configurables:</p><ul><li>Rutas.</li><li>URLs.</li><li>Topics.</li><li>Consultas SQL.</li><li>Timeouts.</li><li>Estrategias de retry.</li><li>Lectores y escritores.</li></ul><p>Evita valores hardcodeados. Usa parametros siempre que el valor cambie por entorno.</p><h2 id="expression-language" tabindex="-1">Expression Language <a class="header-anchor" href="#expression-language" aria-label="Permalink to &quot;Expression Language&quot;">​</a></h2><p>NiFi Expression Language permite calcular valores desde atributos.</p><p>Ejemplos:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>\${filename}</span></span>
<span class="line"><span>\${filename:toLower()}</span></span>
<span class="line"><span>\${now():format(&quot;yyyy-MM-dd&quot;)}</span></span>
<span class="line"><span>\${source_system:equals(&quot;crm&quot;)}</span></span>
<span class="line"><span>\${fileSize:gt(1048576)}</span></span></code></pre></div><p>Uso tipico en <code>UpdateAttribute</code>:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>landing_path = /raw/\${source_system}/\${now():format(&quot;yyyy/MM/dd&quot;)}</span></span></code></pre></div><p>No abuses de expresiones complejas. Si la logica empieza a ser dificil de leer, separala en pasos o usa una herramienta mas adecuada.</p><h2 id="controller-services" tabindex="-1">Controller services <a class="header-anchor" href="#controller-services" aria-label="Permalink to &quot;Controller services&quot;">​</a></h2><p>Un controller service comparte configuracion entre processors.</p><p>Casos comunes:</p><ul><li><code>DBCPConnectionPool</code> para conexiones JDBC.</li><li><code>JsonTreeReader</code> para leer JSON.</li><li><code>CSVReader</code> para leer CSV.</li><li><code>AvroRecordSetWriter</code> para escribir Avro.</li><li><code>StandardSSLContextService</code> para TLS.</li><li>Schema Registry services.</li></ul><p>Ventajas:</p><ul><li>Menos duplicacion.</li><li>Cambios centralizados.</li><li>Configuracion reutilizable.</li><li>Flujos mas claros.</li></ul><h2 id="record-readers-y-writers" tabindex="-1">Record readers y writers <a class="header-anchor" href="#record-readers-y-writers" aria-label="Permalink to &quot;Record readers y writers&quot;">​</a></h2><p>Los processors <code>Record</code> necesitan servicios de lectura y escritura.</p><p>Ejemplo:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CSVReader -&gt; ConvertRecord -&gt; JsonRecordSetWriter</span></span></code></pre></div><p>Esto permite convertir formato sin escribir codigo.</p><p>Buenas practicas:</p><ul><li>Definir esquemas claros.</li><li>Controlar cabeceras y delimitadores.</li><li>Validar tipos.</li><li>Versionar cambios de esquema.</li></ul><h2 id="parameter-contexts" tabindex="-1">Parameter contexts <a class="header-anchor" href="#parameter-contexts" aria-label="Permalink to &quot;Parameter contexts&quot;">​</a></h2><p>Un parameter context contiene valores usados por el flujo.</p><p>Ejemplo:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>#{sftp.host}</span></span>
<span class="line"><span>#{sftp.input.path}</span></span>
<span class="line"><span>#{kafka.topic}</span></span>
<span class="line"><span>#{db.url}</span></span>
<span class="line"><span>#{max.error.percent}</span></span></code></pre></div><p>Beneficios:</p><ul><li>Separar configuracion de diseno.</li><li>Promocionar el mismo flujo entre entornos.</li><li>Marcar parametros sensibles.</li><li>Reducir cambios manuales.</li></ul><h2 id="parametros-sensibles" tabindex="-1">Parametros sensibles <a class="header-anchor" href="#parametros-sensibles" aria-label="Permalink to &quot;Parametros sensibles&quot;">​</a></h2><p>Usa parametros sensibles para:</p><ul><li>Passwords.</li><li>Tokens.</li><li>Secretos.</li><li>Claves privadas.</li><li>Credenciales de APIs.</li></ul><p>No escribas secretos en labels, nombres de processors, logs ni atributos visibles.</p><h2 id="patron-recomendado" tabindex="-1">Patron recomendado <a class="header-anchor" href="#patron-recomendado" aria-label="Permalink to &quot;Patron recomendado&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Process Group</span></span>
<span class="line"><span>  -&gt; Parameter Context por entorno</span></span>
<span class="line"><span>  -&gt; Controller Services compartidos</span></span>
<span class="line"><span>  -&gt; Processors con referencias a parametros</span></span></code></pre></div><h2 id="checklist" tabindex="-1">Checklist <a class="header-anchor" href="#checklist" aria-label="Permalink to &quot;Checklist&quot;">​</a></h2><ul><li>No hay rutas ni hosts hardcodeados.</li><li>Los servicios compartidos estan centralizados.</li><li>Los parametros sensibles estan marcados como sensibles.</li><li>Los processors <code>Record</code> usan readers/writers consistentes.</li><li>Las expresiones son legibles.</li><li>El flujo puede moverse de dev a prod cambiando parametros.</li></ul>`,44)])])}const h=a(i,[["render",n]]);export{m as __pageData,h as default};
